// Pseudo: merge deltas with secure aggregation placeholder
function aggregateDeltas(deltas, state) {
  // secure-aggregate-friendly merge
  const merged = deltas.reduce((acc, d) => acc + d.value, 0);
  state.total += merged;
  return state;
}
