## Key Concepts

- Local-first feature flags and variant mapping
- Delta configuration updates and offline resilience
- Privacy, data minimization, and compliance
- Cost modeling: storage, fetch bandwidth, maintenance, and break-even analysis

## Code Example

```javascript
// Simple config and selection logic
const FLAGS_KEY = 'ab_flags'
function loadFlags(){
  const raw = localStorage.getItem(FLAGS_KEY); return raw ? JSON.parse(raw) : {};
}
function selectVariant(flagName, userHash){
  const flags = loadFlags();
  const flag = flags[flagName];
  if(!flag) return null;
  // deterministic variant from user hash
  const idx = Math.abs(hashCode(userHash + flagName)) % flag.variants.length;
  return flag.variants[idx];
}
function hashCode(s){ let h=0; for(let i=0;i<s.length;i++){ h = (h<<5) - h + s.charCodeAt(i); h |= 0; } return h; }
```

